/// Compress a server-to-client packet.
///
/// Appends the terminator, so the output is a complete stream. The result can be
/// *longer* than the input — the table is tuned for typical packet content, and
/// incompressible bytes cost more than eight bits each. Callers that care must
/// compare and decide; this function always compresses.
///
/// ```
/// use openshard_protocol::huffman;
///
/// let packet = [0x1Bu8, 0x00, 0x00, 0x00, 0x01];
/// let wire = huffman::compress(&packet);
/// assert_eq!(huffman::decompress(&wire).unwrap(), packet);
/// ```
pub fn compress(input: &[u8]) -> Vec<u8> {
    // Most packets shrink; this is a guess, not a bound.
    let mut output = Vec::with_capacity(input.len());
    let mut accumulator: u8 = 0;
    let mut filled: u8 = 0;

    let mut push_symbol = |symbol: usize, output: &mut Vec<u8>| {
        let entry = CODES[symbol];
        let mut remaining = (entry & 0xF) as u8;
        let code = entry >> 4;
        while remaining > 0 {
            remaining -= 1;
            accumulator = (accumulator << 1) | ((code >> remaining) & 1) as u8;
            filled += 1;
            if filled == 8 {
                output.push(accumulator);
                accumulator = 0;
                filled = 0;
            }
        }
    };

    for byte in input {
        push_symbol(*byte as usize, &mut output);
    }
    push_symbol(TERMINAL, &mut output);

    if filled > 0 {
        // Pad the last byte with zeros on the right. The terminator is what
        // tells the decoder to stop, so these bits are never read — but they
        // must be written, since the wire unit is a byte.
        output.push(accumulator << (8 - filled));
    }
    output
}

/// A compressed stream could not be read.
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
#[non_exhaustive]
pub enum HuffmanError {
    /// The bits ran out before the terminator did. The stream is truncated, or
    /// was never a compressed stream.
    Truncated,
    /// A bit sequence matched no code.
    ///
    /// Unreachable for anything [`compress`] produced; reachable for a corrupt
    /// or hostile capture.
    InvalidCode,
}

impl core::fmt::Display for HuffmanError {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        match self {
            Self::Truncated => f.write_str("compressed stream ended before its terminator"),
            Self::InvalidCode => f.write_str("compressed stream held an unknown code"),
        }
    }
}

impl std::error::Error for HuffmanError {}

/// Decompress a stream produced by [`compress`].
///
/// The client never sends compressed data, so this is not on any hot path. It
/// exists so the encoder can be tested against a real inverse rather than
/// against itself, and so packet captures can be read.
///
/// Decoding walks bit by bit against the table. That is O(bits x table) and slow,
/// which is fine for a function nothing calls in production.
pub fn decompress(input: &[u8]) -> Result<Vec<u8>, HuffmanError> {
    let mut output = Vec::new();
    let mut code: u16 = 0;
    let mut length: u8 = 0;

    for byte in input {
        for shift in (0..8).rev() {
            code = (code << 1) | u16::from((byte >> shift) & 1);
            length += 1;

            // A code is at most 11 bits wide, so anything longer than that
            // cannot become a match no matter what follows.
            if length > MAX_CODE_BITS {
                return Err(HuffmanError::InvalidCode);
            }

            let Some(symbol) = lookup(code, length) else {
                continue;
            };
            if symbol == TERMINAL {
                return Ok(output);
            }
            output.push(symbol as u8);
            code = 0;
            length = 0;
        }
    }

    // Trailing padding bits without a terminator: the stream was cut short.
    Err(HuffmanError::Truncated)
}

/// Widest code in the table. Asserted by a test rather than trusted.
const MAX_CODE_BITS: u8 = 11;

/// Find the symbol whose code is exactly `code` in `length` bits.
///
/// Total because the table is a prefix code: no code is a prefix of another, so
/// at most one entry can match.
fn lookup(code: u16, length: u8) -> Option<usize> {
    CODES
        .iter()
        .position(|entry| (entry & 0xF) as u8 == length && (entry >> 4) == code)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn the_table_is_a_valid_prefix_code() {
        // The property that makes decoding unambiguous. If any code were a
        // prefix of another, a decoder could not know where a symbol ended, and
        // the client would render garbage for some inputs and not others.
        for (i, first) in CODES.iter().enumerate() {
            let (code_a, len_a) = (first >> 4, (first & 0xF) as u8);
            assert!(len_a > 0, "entry {i} has no length");
            assert!(len_a <= MAX_CODE_BITS, "entry {i} is {len_a} bits");
            assert!(code_a < (1 << len_a), "entry {i} code overflows its length");

            for (j, second) in CODES.iter().enumerate().skip(i + 1) {
                let (code_b, len_b) = (second >> 4, (second & 0xF) as u8);
                let (short, long, shift) = if len_a <= len_b {
                    (code_a, code_b, len_b - len_a)
                } else {
                    (code_b, code_a, len_a - len_b)
                };
                assert_ne!(long >> shift, short, "code {i} is a prefix of code {j}");
            }
        }
    }

    #[test]
    fn the_table_matches_spheres_golden_key() {
        // Spot-checks against CHuffman.cpp. The client has this table baked in;
        // a single wrong entry makes it decode noise, so it is pinned here.
        assert_eq!(CODES.len(), 257);
        assert_eq!(CODES[0], 0x0002, "first entry");
        assert_eq!(CODES[1], 0x01F5);
        assert_eq!(CODES[255], 0x0627, "last byte value");
        assert_eq!(CODES[TERMINAL], 0x00D4, "terminator: 0b1101, four bits");
    }

    #[test]
    fn round_trips_a_login_packet() {
        // 0x1B start-of-game, roughly.
        let packet = [
            0x1B, 0x00, 0x00, 0x00, 0x01, 0x00, 0x00, 0x01, 0x90, 0x00, 0x00, 0x00, 0x00,
        ];
        let wire = compress(&packet);
        assert_eq!(decompress(&wire).unwrap(), packet);
    }

    #[test]
    fn round_trips_every_single_byte() {
        for byte in 0..=u8::MAX {
            let wire = compress(&[byte]);
            assert_eq!(decompress(&wire).unwrap(), vec![byte], "byte 0x{byte:02X}");
        }
    }

    #[test]
    fn round_trips_every_byte_pair_boundary() {
        // Two symbols in a row is where bit packing across a byte boundary goes
        // wrong, and the codes are 2..11 bits, so pairs cover every alignment.
        for a in [0u8, 1, 0x7F, 0x80, 0xFE, 0xFF] {
            for b in 0..=u8::MAX {
                let input = [a, b];
                assert_eq!(
                    decompress(&compress(&input)).unwrap(),
                    input,
                    "pair {a:02X} {b:02X}"
                );
            }
        }
    }

    #[test]
    fn round_trips_a_long_packet() {
        let input: Vec<u8> = (0..2000).map(|i| (i % 256) as u8).collect();
        assert_eq!(decompress(&compress(&input)).unwrap(), input);
    }

    #[test]
    fn an_empty_packet_is_just_the_terminator() {
        // 0x00D4 is 0b1101 in four bits, padded right to one byte: 0b1101_0000.
        assert_eq!(compress(&[]), vec![0b1101_0000]);
        assert_eq!(decompress(&compress(&[])).unwrap(), Vec::<u8>::new());
    }

    #[test]
    fn compression_actually_compresses_typical_packets() {
        // Real packets are full of zeros and low bytes, which is what the table
        // is tuned for. If this ever regresses the table is wrong.
        let packet = [0u8; 64];
        assert!(
            compress(&packet).len() < packet.len(),
            "64 zero bytes must shrink"
        );
    }

    #[test]
    fn compression_can_grow_incompressible_data() {
        // Documented, not a bug: a caller that must not grow has to compare.
        let packet: Vec<u8> = (0..64).map(|i| 0x80 + (i % 64)).collect();
        let wire = compress(&packet);
        assert!(
            wire.len() > packet.len(),
            "high bytes cost more than 8 bits each; got {} from {}",
            wire.len(),
            packet.len()
        );
    }

    #[test]
    fn a_truncated_stream_is_an_error_not_a_panic() {
        let wire = compress(&[1, 2, 3, 4, 5, 6, 7, 8]);
        assert_eq!(
            decompress(&wire[..wire.len() - 1]),
            Err(HuffmanError::Truncated)
        );
        assert_eq!(decompress(&[]), Err(HuffmanError::Truncated));
    }

    #[test]
    fn junk_does_not_hang_the_decoder() {
        // Not from a real client, but a capture tool will feed this eventually.
        for junk in [vec![0xFF; 16], vec![0x00; 16], vec![0xAA, 0x55, 0xAA, 0x55]] {
            let _ = decompress(&junk);
        }
    }
}
